index 9f034aba874a..a548078f2ec8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3345,6 +3345,69 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         return new ICmpInst(Pred, BOp0, Neg);
       }
     }
+    // Fold icmp eq/ne (add (ext i1 X), (ext i1 Y)), C for sext/zext booleans.
+    // zext(X) + zext(Y) ∈ {0, 1, 2}
+    // sext(X) + sext(Y) ∈ {0, -1, -2}
+    // sext(X) + zext(Y) ∈ {-1, 0, 1}
+    if (BO->hasOneUse()) {
+    Value *X, *Y;
+    bool IsZext0 = match(BOp0, m_ZExt(m_Value(X))) &&
+                   X->getType()->isIntOrIntVectorTy(1);
+    bool IsZext1 = match(BOp1, m_ZExt(m_Value(Y))) &&
+                   Y->getType()->isIntOrIntVectorTy(1);
+    bool IsSext0 = match(BOp0, m_SExt(m_Value(X))) &&
+                   X->getType()->isIntOrIntVectorTy(1);
+    bool IsSext1 = match(BOp1, m_SExt(m_Value(Y))) &&
+                   Y->getType()->isIntOrIntVectorTy(1);
+
+    if ((IsZext0 || IsSext0) && (IsZext1 || IsSext1)) {
+      // Determine which operand is which kind of extension.
+      Value *SextVal = nullptr, *ZextVal = nullptr;
+      if (IsZext0 && IsZext1) {
+        // Both zext: X and Y are already set correctly.
+      } else if (IsSext0 && IsSext1) {
+        // Both sext: X and Y are already set correctly.
+      } else if (IsSext0 && IsZext1) {
+        SextVal = X;
+        ZextVal = Y;
+      } else if (IsZext0 && IsSext1) {
+        SextVal = Y;
+        ZextVal = X;
+      }
+
+      // Create the boolean expression for "sum == C", then invert if ne.
+      auto CreateEqCond = [&]() -> Value * {
+        if ((IsZext0 && IsZext1) || (IsSext0 && IsSext1)) {
+          bool IsZext = IsZext0 && IsZext1;
+          if ((IsZext && C.isZero()) || (!IsZext && C.isZero()))
+            return Builder.CreateNot(Builder.CreateOr(X, Y));
+          if ((IsZext && C.isOne()) || (!IsZext && C.isAllOnes()))
+            return Builder.CreateXor(X, Y);
+          if ((IsZext && C == 2) || (!IsZext \&\& C.getSExtValue() == -2))
+            return Builder.CreateAnd(X, Y);
+        } else {
+          // Mixed sext and zext.
+          if (C.isAllOnes()) // -1: sext=1, zext=0
+            return Builder.CreateAnd(SextVal, Builder.CreateNot(ZextVal));
+          if (C.isZero()) // 0: X == Y
+            return Builder.CreateNot(Builder.CreateXor(X, Y));
+          if (C.isOne()) // 1: sext=0, zext=1
+            return Builder.CreateAnd(ZextVal, Builder.CreateNot(SextVal));
+        }
+        return nullptr;
+      };
+
+      if (Value *EqCond = CreateEqCond()) {
+        if (!isICMP_NE)
+          return replaceInstUsesWith(Cmp, EqCond);
+        // For ne, invert the condition.
+        Value *NotCond = Builder.CreateNot(EqCond);
+        return replaceInstUsesWith(Cmp, NotCond);
+      }
+
+      // For out-of-range constants: eq always false, ne always true.
+      return replaceInstUsesWith(Cmp, ConstantInt::getBool(Cmp.getType(), isICMP_NE));
+    }
     break;
   }
   case Instruction::Xor:

